from machine import Pin, ADC
import time
import network
from umqtt.simple import MQTTClient

# Connect to WiFi
ssid = 'your_ssid'
password = 'your_password'
station = network.WLAN(network.STA_IF)

station.active(True)
station.connect(ssid, password)

while not station.isconnected():
    pass

print("Connected to WiFi")

# Setup ADC for temperature sensor
adc = ADC(Pin(34))
adc.atten(ADC.ATTN_11DB)  # Configure range
adc.width(ADC.WIDTH_12BIT)  # Set width to 12 bits

# MQTT settings
client_id = 'esp32_sensor'
broker_ip = 'broker_ip'
topic = 'sensors/temp'

# Create MQTT client
client = MQTTClient(client_id, broker_ip)

# Connect to the MQTT broker
client.connect()

try:
    while True:
        # Read temperature from sensor
        temp_value = adc.read()
        
        # Convert to temperature in Celsius
        temperature = (temp_value / 4095.0) * 100
        
        # Publish temperature to MQTT broker
        client.publish(topic, str(temperature))
        
        print("Published: {} to {}".format(temperature, topic))
        
        # Delay before sending the next reading
        time.sleep(10)
        
finally:
    client.disconnect()